import { createContext, useContext, useState, useEffect } from 'react';
import { HTMLHuelNotificationElement } from 'huel-notification';

interface NotificationProps {
  heading: string;
  subheading: string;
  type: string;
}

const NotificationContext = createContext(null);

export const useNotification = () => {
  const notificationElem = useContext(NotificationContext);
  const [notificationError, setNotificationError] = useState(null);

  useEffect(() => {
    if (!notificationElem) {
      setNotificationError(new Error('Notification element not found'));
    }
  }, [notificationElem]);

  const notify = async (props: NotificationProps) => {
    if (!notificationElem) {
      throw new Error('Notification element not found');
    }

    try {
      const { heading, subheading, type } = props;
      await notificationElem.open({
        heading,
        subheading,
        type,
      });
    } catch (error) {
      setNotificationError(error);
    }
  };

  return { notify, notificationError };
};

export default NotificationContext;
